import React from 'react';
import { useFormik } from 'formik';
import './App.css'; 
import Main from './main';
import { BrowserRouter, Route, Routes, useNavigate } from 'react-router-dom';

const SignupForm = () => {
  const navigate = useNavigate();

  const formik = useFormik({
    initialValues: {
      Name: '',
      Address: '',
      mobile: '',
      city: '',
      district: '',
      census: '',
      feeder:  '',
      subdivision:  '',
      routecode:  '',
      billmonth:  '',
      billdate:  '',
      duedate:  '',
      fromdate:  '',
      todate:  '',
    },
    onSubmit: (values) => {
      navigate('/main');
    },
  });


  // const handleClick = (e) => {
  //   navigate('/main');
  // };  

  return (
    <div className="form-page">
      <h2>Enter Forms Details</h2>
    <form onSubmit={formik.handleSubmit} className='form-container'>

    <div className='input-main'>
      <div className='b1-input'>
      <label htmlFor="Name">Full Name :</label><br />
      <input   name="Name" type="text" onChange={formik.handleChange} value={formik.values.Name} required /><br /><br />

      <label htmlFor="Address">Address :</label><br />
      <input  name="Address" type="text" onChange={formik.handleChange} value={formik.values.Address} required /><br /><br />

      <label htmlFor="Mobile">Mobile Number :</label><br />
      <input  name="mobile" type="text" onChange={formik.handleChange} value={formik.values.mobile} required /><br /><br />

      <label htmlFor="city">City :</label><br />
      <input  name="city" type="text" onChange={formik.handleChange} value={formik.values.city} required /><br /><br />

      <label htmlFor="district">District :</label><br />
      <input  name="district" type="text" onChange={formik.handleChange} value={formik.values.district} required /><br /><br />

      <label htmlFor="census">Census Code :</label><br />
      <input  name="census" type="text" onChange={formik.handleChange} value={formik.values.census} required /><br /><br />

      <label htmlFor="feeder">Feeder Code :</label><br />
      <input  name="feeder" type="text" onChange={formik.handleChange} value={formik.values.feeder} required /><br /><br />
    </div>

    <div className='b2-input'>
      <label htmlFor="subdivision">Subdivision Name :</label><br />
      <input   name="subdivision" type="text" onChange={formik.handleChange} value={formik.values.subdivision} required /><br /><br />

      <label htmlFor="routecode">Route Code :</label><br />
      <input  name="routecode" type="text" onChange={formik.handleChange} value={formik.values.routecode} required /><br /><br />

      <label htmlFor="billmonth">Bill Month :</label><br />
      <input  name="billmonth" type="text" onChange={formik.handleChange} value={formik.values.billmonth} placeholder='e.g: Oct , 2025' required /><br /><br />

      <label htmlFor="billdate">Bill Date :</label><br />
      <input className="init" name="billdate" type="date" onChange={formik.handleChange} value={formik.values.billdate} required /><br /><br />

      <label htmlFor="duedate">Due Date :</label><br />
      <input className="init" name="duedate" type="date" onChange={formik.handleChange} value={formik.values.duedate} required /><br /><br />

      <label htmlFor="fromdate">From Date :</label><br />
      <input className="init" name="fromdate" type="date" onChange={formik.handleChange} value={formik.values.fromdate} required /><br /><br />
      <label htmlFor="todate">To Date :</label><br />
      <input className="init" name="todate" type="date" onChange={formik.handleChange} value={formik.values.todate} required /><br /><br />
    </div>
    </div>

   <div className='btn-box'>
      <button style={{backgroundColor:'red', borderRadius:5, color:"white"}} type="submit" >Submit</button>
    </div>
    </form>
    </div>
  );
};

export default function App() {
  return (
    <BrowserRouter>
    <Routes>
      <Route path="/" element={<SignupForm />} />
      <Route path="/main" element={<Main />} />
    </Routes>
    </BrowserRouter>
  );
}
